A debounce function delays the execution of a function until after a specified wait time has passed without it being called again, useful for optimizing performance in event handlers like `input` or `scroll`.

```javascript
function debounce(func, wait) {
  let timeout;
  return function executedFunction(...args) {
    const later = () => {
      clearTimeout(timeout);
      func(...args);
    };
    clearTimeout(timeout);
    timeout = setTimeout(later, wait);
  };
}

// Example usage:
const inputHandler = debounce((event) => {
  console.log('Input value:', event.target.value);
}, 300);

document.getElementById('searchInput').addEventListener('input', inputHandler);
```
